UPDATE products SET blurb = 'Spearmint is a hardy perennial mint with bright green serrated leaves. Mentha x spicata was originally native to the Mediterranean but is now common worldwide.', description = 'Spearmint is a hardy perennial mint with bright green serrated leaves. Mentha x spicata was originally native to the Mediterranean but is now common worldwide. This mint is most commonly infused as spearmint tea and makes for an uplifting addition to herbal infusion blends. Spearmint leaf is also used as a flavoring agent in culinary creations.

